INSERT INTO `pages` (`id`, `parent_id`, `title`, `slug`, `full_slug`, `meta_title`, `meta_description`, `body_json`, `template`, `status`, `author_id`, `reviewed_by`, `reviewed_at`, `published_at`, `noindex`, `robots_follow`, `sort`, `created_by`, `updated_by`, `canonical_url`, `og_image`, `featured_image`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, NULL, 'About Us', 'about', NULL, 'About Us', 'Learn more about our company and mission.', '{\"blocks\":[{\"type\":\"heading\",\"content\":\"About Our Company\"},{\"type\":\"paragraph\",\"content\":\"Northern Tile Distributors is a leading tile shop in Thomastown, Melbourne, built on a genuine passion for tiles and flooring. What started as a passion-driven vision backed by decades of hands-on industry experience has grown into one of Melbourne\\u2019s most trusted destinations for premium tiles, hybrid flooring, timber, and stone.\\r\\n\\r\\nFrom the very beginning, our mission has been simple \\u2014 to help people find the perfect flooring solution at a price that works for them. Whether you are searching for tiles in Melbourne, hybrid flooring in Melbourne, or a reliable tile store in Thomastown, our team is committed to delivering quality, value, and expert guidance.\\r\\n\\r\\nLocated in Thomastown, Melbourne, we proudly serve homeowners, builders, and designers across Melbourne\\u2019s northern suburbs and beyond. Our reputation is built on honest advice, premium-quality products, and service that genuinely goes the extra mile.\\r\\n\\r\\nWhat truly sets us apart is our team. Every member of Northern Tile Distributors is driven by a passion for tiles and flooring and brings 10+ years of real industry experience. Having helped thousands of satisfied customers over the years, our team understands how to match the right tile, flooring, and design to each unique space. When you walk into our showroom or shop online, you are not just buying products \\u2014 you are receiving guidance from experts who know what works and why.\\r\\n\\r\\nWe stock a comprehensive range of products, including:\\r\\n\\r\\nPremium wall and floor tiles\\r\\nHybrid flooring and hybrid timber solutions\\r\\nEngineered timber flooring\\r\\nNatural stone and marble\\r\\nOutdoor 20mm pavers\\r\\n\\r\\nWhether you are renovating a bathroom, upgrading your living space, or managing a large-scale build, we can also create complete house packages to cover all your flooring and tile requirements in one place.\\r\\n\\r\\nAt Northern Tile Distributors, we are more than just a tile store in Melbourne \\u2014 we help you create spaces that are stylish, functional, and built to last.\\r\\n\\r\\nVisit our showroom in Thomastown or explore our collection online at www.ntiled.com.au\"}]}', 'about', 'published', NULL, NULL, NULL, '2026-04-03 05:43:00', 0, 1, 0, NULL, 3, NULL, NULL, NULL, '2026-04-03 05:43:54', '2026-05-11 04:02:23', NULL),
(2, NULL, 'Privacy Policy', 'privacy-policy', NULL, 'Privacy Policy', 'Our privacy policy explains how we collect and use your data.', '{\"blocks\":[{\"type\":\"heading\",\"content\":\"Privacy Policy\"},{\"type\":\"paragraph\",\"content\":\"This privacy policy describes how we handle your personal information.\"}]}', 'default', 'published', NULL, NULL, NULL, '2026-04-03 05:43:54', 0, 1, 0, NULL, NULL, NULL, NULL, NULL, '2026-04-03 05:43:54', '2026-04-03 05:43:54', NULL),
(3, NULL, 'Terms of Service', 'terms-of-service', NULL, 'Terms of Service', 'Read our terms of service before using our website.', '{\"blocks\":[{\"type\":\"heading\",\"content\":\"Terms of Service\"},{\"type\":\"paragraph\",\"content\":\"By using our services, you agree to these terms.\"}]}', 'default', 'published', NULL, NULL, NULL, '2026-04-03 05:43:54', 0, 1, 0, NULL, NULL, NULL, NULL, NULL, '2026-04-03 05:43:54', '2026-04-03 05:43:54', NULL),
(4, NULL, 'Return Policy', 'return-policy', NULL, 'Return Policy', 'Learn about our return and refund policy.', '{\"blocks\":[{\"type\":\"heading\",\"content\":\"Return Policy\"},{\"type\":\"paragraph\",\"content\":\"We offer hassle-free returns within 30 days of purchase.\"}]}', 'default', 'published', NULL, NULL, NULL, '2026-04-03 05:43:54', 0, 1, 0, NULL, NULL, NULL, NULL, NULL, '2026-04-03 05:43:54', '2026-04-03 05:43:54', NULL);
